#!/usr/bin/env python3
"""mkt-christ commentary — Joshua 24 (covenant renewal at Shechem: Christological typology)
Run: python3 scripts/zc-christ-joshua-24-24.py
Key types: covenant mediator (v.25/Heb 9:15), Heilsgeschichte in Christ (vv.2-13/2 Cor 1:20),
"choose whom you will serve" (v.15/Matt 6:24), "you are not able" (v.19/Rom 8:3),
Joseph's bones / faith that spans (v.32/Heb 11:22), Eleazar / no successor needed (v.33/Heb 7:24)
"""
import json
from pathlib import Path

ROOT = Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

DATA = {
  "24": {
    "1": "<p>Joshua assembles all the tribes at <strong>Shechem</strong> — the site where Abraham first entered Canaan and built an altar to YHWH (<a class='ref' data-ref='Gen 12:6-7'>Gen 12:6–7</a>), where Jacob buried foreign gods (<a class='ref' data-ref='Gen 35:4'>Gen 35:4</a>), and where the blessings and curses were proclaimed after Ai (<a class='ref' data-ref='Josh 8:33'>Josh 8:33</a>). Every covenant renewal at Shechem involves the removal of idols and the reassertion of YHWH's exclusive claim. Christ chooses the same geography for a covenant conversation: the Samaritan woman at Sychar/Shechem (<a class='ref' data-ref='John 4:5-6'>John 4:5–6</a>), near Jacob's well, where he declares himself the source of living water — the new covenant meeting at the place of the old.</p>",
    "2": "<p>The assembly opens with <em>kōh ʾāmar YHWH</em> — the prophetic messenger formula: \"Thus says the LORD.\" Joshua speaks not in his own name but as YHWH's authorized mouthpiece, introducing the Heilsgeschichte in YHWH's first-person voice. Christ uses the same authority — but surpasses the formula. Moses and Joshua prefaced their words with \"thus says the LORD\"; Jesus says \"<em>Egō de legō hymin</em> — but I say to you\" (<a class='ref' data-ref='Matt 5:22'>Matt 5:22</a>). He does not relay YHWH's word; he speaks as the Word himself (<a class='ref' data-ref='John 1:1'>John 1:1</a>).</p>",
    "3": "<p>YHWH's first-person verb chain begins: \"I took Abraham... I led him... I multiplied his offspring.\" The Heilsgeschichte is a cascade of divine actions with Abraham as the passive recipient — he is taken, led, multiplied. God's own initiative is the exclusive subject. Galatians 3:16: \"The promises were spoken to Abraham and to his seed... that is, to Christ.\" The entire chain of divine initiative from Genesis 12 to Joshua 24 has its terminus and fulfillment in Christ, the singular seed in whom all the \"I took, I gave, I multiplied\" actions find their goal.</p>",
    "4": "<p>YHWH gave Jacob and Esau; he gave Esau the hill country of Seir. The Heilsgeschichte includes the non-elect as well as the elect — YHWH's sovereignty extends over all nations' land distributions, not only Israel's. Paul works the same logic in Romans 9–11: election is sovereign, not automatic by birth, and God's purposes include what he does with the non-elect as well. Christ as the true Israel is the one in whom YHWH's electing purposes concentrate before flowing outward to all nations.</p>",
    "5": "<p>\"I sent Moses and Aaron, and I plagued Egypt.\" The ten plagues are YHWH's direct action against Pharaoh's gods and Pharaoh himself — the judgment that precedes the exodus. Christ is the greater Moses sent by the Father (<a class='ref' data-ref='John 5:36'>John 5:36</a>; <a class='ref' data-ref='Deut 18:18'>Deut 18:18</a>). The plagues' final climax — death of the firstborn, overridden by the blood of the lamb — is the decisive type: Christ as the Passover Lamb whose blood is the only protection from divine judgment (<a class='ref' data-ref='1 Cor 5:7'>1 Cor 5:7</a>).</p>",
    "6": "<p>\"I brought your ancestors out of Egypt and you came to the sea; the Egyptians pursued with chariots and horsemen.\" The danger of the sea — the superior military force behind, the uncrossable water ahead — mirrors the impossible situation of sinners trapped between guilt behind and death ahead. The Red Sea crossing is Paul's type for baptism: \"all were baptized into Moses in the cloud and in the sea\" (<a class='ref' data-ref='1 Cor 10:1-2'>1 Cor 10:1–2</a>). Christ leads his people through the waters of death into the promised inheritance.</p>",
    "7": "<p>YHWH put darkness between Israel and the Egyptians and brought the sea back over them. The darkness that protects the covenant people while destroying the enemy anticipates the darkness of the crucifixion: three hours of darkness over the land (<a class='ref' data-ref='Matt 27:45'>Matt 27:45</a>) while the powers of darkness exhaust themselves against the Son of God, only to be destroyed by what they intended as their weapon. \"I did this while your eyes watched\" — the witnesses of the exodus testify; the witnesses of the resurrection testify.</p>",
    "8": "<p>\"I gave the Amorites into your hand.\" YHWH fights Israel's battles directly; the Amorites are destroyed not by Israel's military superiority but by divine gift. The same pattern governs Christ's victory over the powers: \"He disarmed the rulers and authorities and put them to open shame, by triumphing over them in him\" (<a class='ref' data-ref='Col 2:15'>Col 2:15</a>). The enemy is handed over — it is YHWH who delivers them, not Israel's arm or Christ's human strength.</p>",
    "9": "<p>Balak son of Zippor rose and warred against Israel — and sent for Balaam to curse God's people. The attempt to place a covenant curse on Israel by hiring a prophet to speak YHWH's words against them is a demonic inversion of the prophetic office: using YHWH's own medium to oppose YHWH's purposes. Christ endured the same satanic strategy: the temptation to use Scripture against his mission (<a class='ref' data-ref='Matt 4:6'>Matt 4:6</a>). The enemy knows the words; only the Word himself knows the meaning.</p>",
    "10": "<p>\"But I would not listen to Balaam; therefore he blessed you again and again, and I delivered you from his hand.\" Every curse intended against the covenant people was reversed into blessing — not by Israel's merit but by YHWH's refusal to be weaponized against his own. This is the gospel's logic: \"Christ redeemed us from the curse of the law by becoming a curse for us\" (<a class='ref' data-ref='Gal 3:13'>Gal 3:13</a>). The intended curse was absorbed and reversed; the blessing breaks through.</p>",
    "11": "<p>Israel crossed the Jordan; YHWH drove out the Jericho coalition and the seven Canaanite nations before them. The conquest is entirely YHWH's gift — Israel marches, but YHWH expels. Romans 8:31: \"If God is for us, who can be against us?\" The nations arrayed against God's people are overcome not by greater human power but by the presence of the covenant LORD. Christ's victory over every power and authority is the ultimate fulfillment: he \"must reign until he has put all enemies under his feet\" (<a class='ref' data-ref='1 Cor 15:25'>1 Cor 15:25</a>).</p>",
    "12": "<p>YHWH sent the <em>ṣirʿāh</em> (hornets/terror) before Israel — \"not by your sword or your bow.\" The weapon is divine, not human; the defeat of the two Amorite kings was YHWH's work, not Israel's military effort. This is the theology of the cross: \"not by might, nor by power, but by my Spirit, says the LORD\" (<a class='ref' data-ref='Zech 4:6'>Zech 4:6</a>). Paul in 1 Corinthians 1:27–28: \"God chose what is foolish... what is weak... what is low and despised.\" The cross — the instrument of shame — is the weapon that defeats every power.</p>",
    "13": "<p>\"I gave you a land you did not labor on, cities you did not build, vineyards and olive groves you did not plant.\" The gift is entirely unearned — city, field, orchard — all receive-not-produce. This is the grammar of grace: Deuteronomy 6:10–11 rehearses the same list; Paul's \"you were washed, you were sanctified, you were justified\" (<a class='ref' data-ref='1 Cor 6:11'>1 Cor 6:11</a>) follows the same passive structure. The righteousness that is \"not from me... that comes through faith in Christ\" (<a class='ref' data-ref='Phil 3:9'>Phil 3:9</a>) is the vineyard we did not plant, the city we did not build.</p>",
    "14": "<p>\"Fear the LORD and serve him with <em>tāmîm ûbĕʾĕmet</em> — complete integrity and faithfulness.\" The standard required is total: no divided loyalty, no hidden compromise. Christ alone served YHWH with this completeness — he was the only one who could say \"I always do what pleases him\" (<a class='ref' data-ref='John 8:29'>John 8:29</a>). In him, his people are counted as having served with this wholeness; his obedience is credited to those who are in him. The covenant demand is not abolished but fulfilled representatively.</p>",
    "15": "<p>\"If you are unwilling to serve the LORD, choose today whom you will serve.\" The covenant is not coerced; YHWH presents the choice and demands a decision. Christ echoes this binary: \"No one can serve two masters\" (<a class='ref' data-ref='Matt 6:24'>Matt 6:24</a>); \"I am the way, the truth, and the life; no one comes to the Father except through me\" (<a class='ref' data-ref='John 14:6'>John 14:6</a>). \"But as for me and my house, we will serve the LORD\" — Joshua's household declaration becomes the pattern of Christian confession: the explicit, public, household-level commitment to Christ over all competing loyalties (<a class='ref' data-ref='Acts 16:31'>Acts 16:31</a>).</p>",
    "16": "<p><em>Ḥālîlāh</em> — \"Far be it from us to forsake the LORD!\" The oath-like repudiation formula signals genuine horror at the thought of abandoning YHWH. Peter's response when Jesus asks \"Will you also go away?\" — \"Lord, to whom shall we go? You have the words of eternal life\" (<a class='ref' data-ref='John 6:68'>John 6:68</a>) — is the New Testament <em>ḥālîlāh</em>: the true disciple cannot imagine an alternative to Christ, not because of coercion, but because there is nowhere else the living word is heard.</p>",
    "17": "<p>The people repeat the Heilsgeschichte back to Joshua: \"For the LORD our God, <em>hûʾ</em> — he himself — is the one who brought us up from Egypt.\" The emphatic <em>hûʾ</em> (he, himself) is a declaration of exclusive identity: this God and no other. The Christian confession works the same way: \"Jesus is Lord\" — not \"a lord\" or \"our preferred deity\" but the one through whom all things were made and through whom all redemption comes (<a class='ref' data-ref='1 Cor 8:6'>1 Cor 8:6</a>).</p>",
    "18": "<p>\"YHWH drove out before us all the peoples, including the Amorites.\" The people internalize the conquest as YHWH's act on their behalf and therefore commit: \"We also will serve the LORD.\" Covenant gratitude precedes covenant obligation — the indicative grounds the imperative. Paul's ethical instruction always follows this order: \"I appeal to you therefore, brothers, by the mercies of God\" (<a class='ref' data-ref='Rom 12:1'>Rom 12:1</a>). The Heilsgeschichte is the motivation, not the means, of covenant faithfulness.</p>",
    "19": "<p>\"You are not able to serve the LORD.\" Joshua's shocking counter-statement after the people's enthusiastic commitment is not discouragement but diagnosis: human confidence in one's own covenant-keeping is itself the problem. This is Paul's argument in Romans 7–8: \"the mind of the flesh is death... it does not submit to God's law; indeed, it cannot\" (<a class='ref' data-ref='Rom 8:6-7'>Rom 8:6–7</a>). What the law could not do in that it was weak through the flesh, God accomplished by sending his Son (<a class='ref' data-ref='Rom 8:3-4'>Rom 8:3–4</a>). The people's \"We will serve the LORD\" requires a mediator who can serve YHWH on their behalf.</p>",
    "20": "<p>\"If you forsake the LORD and serve foreign gods, he will turn and harm you.\" The covenant curse: <em>wĕšāb wĕhērāʿ</em> — he will turn and do evil against you. This is the <em>wrath of God</em> — not capricious but covenantally structured. Romans 1:18–32 describes the same dynamic: God \"gives them over\" when they exchange his glory for idols. The New Testament does not soften the covenant curse; it intensifies it — and then absorbs it in Christ: \"he became a curse for us\" (<a class='ref' data-ref='Gal 3:13'>Gal 3:13</a>), taking the <em>wĕhērāʿ</em> that covenant-breakers deserve.</p>",
    "21": "<p>\"No! We will serve the LORD.\" The people push back against Joshua's warning — doubling down after the stark diagnosis of their inability. This is not the confidence of arrogance but the desperation of those who have nowhere else to go. The same doubling-down marks true disciples: when many turned away from Jesus's hard teaching, those who remained said \"Lord, to whom shall we go?\" (<a class='ref' data-ref='John 6:68'>John 6:68</a>). True faith persists through the diagnosis of weakness rather than retreating from it.</p>",
    "22": "<p>\"You are witnesses against yourselves that you have chosen the LORD.\" <em>ʿēdîm ʾattem bākem</em> — the covenant community's confession becomes legal self-testimony. This self-binding by verbal commitment is the structure of all covenant oaths. Christ applies the same principle: \"By your words you will be justified, and by your words you will be condemned\" (<a class='ref' data-ref='Matt 12:37'>Matt 12:37</a>). The spoken confession of faith is both a grace and a legal self-incrimination before the divine court — which is why it requires a mediator who can answer for the confessor's failures.</p>",
    "23": "<p>\"Put away the foreign gods that are among you.\" The same command Jacob gave at Shechem (Gen 35:2), now repeated by Joshua — the covenant assembly's recurring demand. John's first letter ends with the same command: \"Little children, keep yourselves from idols\" (<a class='ref' data-ref='1 John 5:21'>1 John 5:21</a>). Colossians 3:5: \"Put to death... covetousness, which is idolatry.\" The gods must be put away because YHWH's jealousy (<em>qannōʾ</em>, v.19) accepts no rivals; Christ's lordship is total or it is nothing.</p>",
    "24": "<p>\"The LORD our God we will serve, and his voice we will obey.\" The double commitment pairs <em>ʿābad</em> (serve/worship) with <em>šāmaʿ bĕqôl</em> (hear-obey). Christ's definition of his sheep: \"My sheep hear my voice... and they follow me\" (<a class='ref' data-ref='John 10:27'>John 10:27</a>). The covenant pledge of Joshua 24 is fulfilled in those who not only know who speaks but recognize the voice as the one voice they will follow — not reluctantly, but because it is their life.</p>",
    "25": "<p>Joshua cuts the covenant — <em>kārat bĕrît</em> — and sets statute and ordinance at Shechem. The three legal terms (<em>bĕrît, ḥōq, mišpāṭ</em>) describe a fully constituted treaty relationship. Christ is the mediator of a better covenant enacted on better promises (<a class='ref' data-ref='Heb 8:6'>Heb 8:6</a>); his Last Supper enacts the new covenant in his blood (<a class='ref' data-ref='Luke 22:20'>Luke 22:20</a>): the covenant cut not with animal blood but with his own. Hebrews 9:15: \"He is the mediator of a new covenant, so that those who are called may receive the promised eternal inheritance.\"</p>",
    "26": "<p>Joshua writes these things in <em>sēper tôrat ʾĕlōhîm</em> — the Book of God's Law — and sets a stone under the oak at YHWH's sanctuary. The law written on stone and in a scroll anticipates its internalization: Jeremiah 31:33 promises that the new covenant law will be written on hearts; 2 Corinthians 3:3 says believers are \"a letter from Christ... written not with ink but with the Spirit of the living God, not on tablets of stone but on tablets of human hearts.\" The external witness-stone of Shechem gives way to the internal witness of the Spirit (<a class='ref' data-ref='Rom 8:16'>Rom 8:16</a>).</p>",
    "27": "<p>\"This stone shall be a witness against us, for it has heard all the words of the LORD that he spoke to us.\" The stone as <em>ʿēd</em> (legal witness) endures when human memory fades. Christ applied the principle: \"If these were silent, the very stones would cry out\" (<a class='ref' data-ref='Luke 19:40'>Luke 19:40</a>). Creation itself testifies to the covenant LORD. Revelation 2:17 promises \"a white stone with a new name\" to the overcomer — the final covenant witness stone is Christ's own declaration of the believer's identity, written by him who cannot forget.</p>",
    "28": "<p>\"Joshua dismissed the people, each to his inheritance.\" The <em>naḥălāh</em> — the word that governed the entire distribution narrative of chapters 13–22 — is the note on which the assembly ends. They go to what YHWH gave, carrying the covenant obligation. The New Testament equivalent: \"Go... and make disciples\" (<a class='ref' data-ref='Matt 28:19'>Matt 28:19</a>) — the assembly is dismissed to their inheritance, now the whole earth, to declare the covenant of the one who gives it.</p>",
    "29": "<p>Joshua son of Nun, <strong>ʿebed YHWH</strong> — servant of the LORD — dies at 110. The title <em>ʿebed YHWH</em> was Moses's distinctive honor throughout the book; here at Joshua's death it transfers to Joshua, formally elevating him to Mosaic status. Christ is the ultimate <em>ʿebed YHWH</em> — Isaiah's Servant Songs (Isa 42:1; 49:3; 52:13; 53:11) describe the one Moses and Joshua prefigure. He \"made himself nothing, taking the form of a servant\" (<a class='ref' data-ref='Phil 2:7'>Phil 2:7</a>); the Father's \"well done, good and faithful servant\" (<a class='ref' data-ref='Matt 25:21'>Matt 25:21</a>) is the covenant's ultimate <em>ʿebed</em> commendation.</p>",
    "30": "<p>Joshua is buried in <em>naḥălātô</em> — his own inheritance at Timnath-serah. He received his territory last, after all others were settled (Josh 19:49–50); he is buried in what he was given, not what he seized. The one who served YHWH by distributing others' inheritances before his own is buried in the land that was his by promise. Christ \"humbled himself... and was exalted\" (<a class='ref' data-ref='Phil 2:8-9'>Phil 2:8–9</a>) — the order is not reversed until the full work is done. His burial in Joseph of Arimathea's tomb is also a burial in another's inheritance, fitting for the one who makes all inheritance possible.</p>",
    "31": "<p>Israel served the LORD all the days of Joshua and all the days of the elders who outlived him. Covenant faithfulness held for one generation of leadership — then failed (Judges 2:10–12). The old covenant's fragility is exposed: it depended on the faithfulness of leaders and the living memory of witnesses. The new covenant solves this by writing the law on hearts and granting the Spirit: Jeremiah 31:34 promises that \"no longer shall each one teach his neighbor... for they shall all know me\"; Hebrews 8:11 quotes this as the decisive superiority of Christ's covenant over Joshua's.</p>",
    "32": "<p>The bones of Joseph, carried from Egypt by Moses (<a class='ref' data-ref='Exod 13:19'>Exod 13:19</a>) in fulfillment of his deathbed command (<a class='ref' data-ref='Gen 50:25'>Gen 50:25</a>), are buried at Shechem in the field Jacob bought from Hamor. Hebrews 11:22 calls Joseph's instruction about his bones an act of <em>pistis</em> — faith: he knew the God of the promise would bring his people back to the land, and he staked his burial on it. Four generations of promise-keeping land in one burial — Abraham's faith, Jacob's purchase, Joseph's command, Moses's carrying, Joshua's conquest — all converge at Shechem. Christ is the fulfillment of every promise in this chain: \"For all the promises of God find their Yes in him\" (<a class='ref' data-ref='2 Cor 1:20'>2 Cor 1:20</a>).</p>",
    "33": "<p>Eleazar son of Aaron dies and is buried at Gibeah of Phinehas. The book's final verse closes the priestly strand: Eleazar supervised every allotment (Josh 14:1; 17:4; 19:51; 21:1), the priestly mediator between the land-gift and the people. His death requires a successor — Phinehas inherits his place. But Hebrews 7:23–25 identifies this very dynamic as the limitation of the Levitical priesthood: \"the former priests were many in number, because they were prevented by death from continuing in office; but he holds his priesthood permanently, because he lives forever. Consequently, he is able to save to the uttermost those who draw near to God through him, since he always lives to make intercession for them.\" The book closes with three burials — Joshua (warrior-covenant), Joseph (patriarch-faith), Eleazar (priestly mediation) — all three streams requiring successors; Christ fulfills all three as the one who needs none.</p>"
  }
}

if __name__ == '__main__':
    il = json.loads((ROOT / 'data' / 'interlinear' / 'joshua.json').read_text())
    existing = load_comm('mkt-christ', 'joshua')
    merge_comm(existing, DATA)
    save_comm('mkt-christ', 'joshua', existing)

    all_ok = True
    expected = set(il['24'].keys())
    got = set(existing.get('24', {}).keys())
    missing = expected - got
    if missing:
        print(f'ch 24: MISSING verses {sorted(missing, key=int)}')
        all_ok = False
    else:
        print(f'ch 24: complete ({len(got)} verses)')

    if all_ok:
        chs_done = sorted(existing.keys(), key=int)
        print(f'All verses present ✓')
        print(f'Joshua mkt-christ chapters now: {chs_done} ({len(chs_done)}/24)')
    else:
        print('INCOMPLETE — fix missing verses above')
